/**
 * Optional: write latest snapshot JSON to Drive for durable export.
 * Requires Drive scope prompt.
 */
function MB_snapshotToDrive(filenamePrefix) {
  const ledger = MB_getLedger_();
  const snaps = ledger.snapshots || [];
  if (!snaps.length) throw new Error("MB_snapshotToDrive: no snapshots yet.");

  const last = snaps[snaps.length - 1];
  const name = (filenamePrefix || "MB_SNAPSHOT") + "_" + (last.timestamp || "").replace(/[:.]/g, "-") + ".json";
  const blob = Utilities.newBlob(JSON.stringify(last, null, 2), "application/json", name);
  const file = DriveApp.createFile(blob);
  return { ok: true, fileId: file.getId(), name: file.getName() };

}

